// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.subtopic = $('Loop Over Items').first().json.subtopic
}

return $input.all();

// Input contoh: { title, article: [{subtopic, output}, ...] }
const title = $('Generate Outline').first().json.output.topic;
const items = Array.isArray($input.first().json.data) ?  $input.first().json.data: [];

const norm = (v) => (v ?? '').toString().trim();
const para = (t) => t
  .split(/\n{2,}/).map(s => s.trim()).filter(Boolean)
  .map(s => `<p>${s}</p>`).join('\n');

let md = '';
let html = '';

// 1) Item pertama: hanya output
if (items[0]) {
  const out0 = norm(items[0].output);
  if (out0) {
    md += `${out0}\n\n`;
    html += para(out0) + '\n\n';
  }
}

// 2) Sisanya: subtopic lalu output
for (let i = 1; i < items.length; i++) {
  const st = norm(items[i].subtopic);
  const out = norm(items[i].output);

  if (st) {
    md += `## ${st}\n\n`;
    html += `<h2>${st}</h2>\n`;
  }
  if (out) {
    md += `${out}\n\n`;
    html += para(out) + '\n\n';
  }
}

// Optional: ringkas spasi
md = md.replace(/\n{3,}/g, '\n\n').trim();
html = html.replace(/\n{3,}/g, '\n\n').trim();

// Keluaran untuk node berikutnya (HTTP Request -> WordPress)
return [
  {
    json: {
      title,
      content_markdown: md,
      content_html: html,           // for Rest API
    }
  }
];
